// FString — general manipulation
FString PlayerName = TEXT("Hero");
FString Greeting = FString::Printf(TEXT("Welcome, %s! Level %d"), *PlayerName, Level);
bool bHasPrefix = Greeting.StartsWith(TEXT("Welcome"));
FString Upper = Greeting.ToUpper();

// FName — fast identifier
FName BoneName = TEXT("head");
FName SocketName = TEXT("weapon_r");
FName RowName = TEXT("Sword_01");
if (Hit.BoneName == BoneName) { /* headshot */ }

// FText — player-facing UI text
#define LOCTEXT_NAMESPACE "MyGame"
FText WelcomeText = LOCTEXT("WelcomeMsg", "Welcome to the game!");
FText DamageText = FText::Format(
    LOCTEXT("DamageFmt", "{0} dealt {1} damage to {2}"),
    FText::FromString(AttackerName),
    FText::AsNumber(DamageAmount),
    FText::FromString(VictimName)
);
#undef LOCTEXT_NAMESPACE

// Conversions
FString Str = TEXT("Hello");
FName Name = FName(*Str);           // FString -> FName
FString Back = Name.ToString();     // FName -> FString
FText Txt = FText::FromString(Str); // FString -> FText
FString FromTxt = Txt.ToString();   // FText -> FString
